# How to Add a React Component

Step-by-step guide for adding React components to the web apps.

## Prerequisites

- Web app at `apps/quarry-web/` or `apps/smithy-web/`
- Understanding of React + TypeScript
- Familiarity with Tailwind CSS

## Component Types

| Type | Location | Purpose |
|------|----------|---------|
| UI Primitive | `packages/ui/src/components/` | Reusable buttons, inputs, badges, etc. (shared `@stoneforge/ui` package) |
| Feature Component | `apps/{app}/src/components/{feature}/` | Feature-specific (TaskCard, etc.) |
| Layout Component | `apps/{app}/src/components/layout/` | App shell, sidebar, etc. |
| Shared Component | `apps/{app}/src/components/shared/` | Cross-feature utilities |

## Steps

### 1. Create the Component File

**UI Primitive** (in the shared `@stoneforge/ui` package):
```typescript
// packages/ui/src/components/Badge.tsx
import * as React from 'react';

export interface BadgeProps extends React.HTMLAttributes<HTMLSpanElement> {
  variant?: 'default' | 'primary' | 'success' | 'warning' | 'error' | 'outline';
  size?: 'sm' | 'md';
  children: React.ReactNode;
  className?: string;
}

const variantStyles = {
  default: 'bg-gray-100 text-gray-800',
  primary: 'bg-blue-100 text-blue-800',
  success: 'bg-green-100 text-green-800',
  warning: 'bg-yellow-100 text-yellow-800',
  error: 'bg-red-100 text-red-800',
  outline: 'border border-current bg-transparent',
};

export const Badge = React.forwardRef<HTMLSpanElement, BadgeProps>(
  ({ className = '', variant = 'default', size = 'md', children, ...props }, ref) => {
    return (
      <span
        ref={ref}
        className={[
          'inline-flex items-center rounded-full font-medium',
          size === 'sm' ? 'px-2 py-0.5 text-xs' : 'px-2.5 py-0.5 text-xs',
          variantStyles[variant],
          className,
        ].filter(Boolean).join(' ')}
        {...props}
      >
        {children}
      </span>
    );
  }
);
Badge.displayName = 'Badge';
```

**Feature Component** (in the app):
```typescript
// apps/quarry-web/src/components/task/TaskCard.tsx
import { Task } from '@stoneforge/core';
import { Badge } from '@stoneforge/ui';

interface TaskCardProps {
  task: Task;
  onClick?: () => void;
  className?: string;
}

export function TaskCard({ task, onClick, className }: TaskCardProps) {
  return (
    <div
      className={`p-4 rounded-lg border bg-white hover:shadow-md transition-shadow cursor-pointer ${className ?? ''}`}
      onClick={onClick}
    >
      <div className="flex items-center justify-between">
        <h3 className="font-medium text-gray-900">{task.title}</h3>
        <Badge variant={getStatusVariant(task.status)}>{task.status}</Badge>
      </div>
      {task.tags.length > 0 && (
        <div className="mt-2 flex gap-1">
          {task.tags.map(tag => (
            <span key={tag} className="text-xs text-gray-500">#{tag}</span>
          ))}
        </div>
      )}
    </div>
  );
}

function getStatusVariant(status: string) {
  switch (status) {
    case 'closed': return 'success';
    case 'blocked': return 'error';
    case 'in_progress': return 'warning';
    default: return 'default';
  }
}
```

### 2. Add Data Fetching Hook (if needed)

```typescript
// apps/quarry-web/src/api/hooks/useTaskDetails.ts
import { useQuery } from '@tanstack/react-query';
import { Task } from '@stoneforge/core';

const API_BASE = import.meta.env.VITE_API_URL || '';

export function useTaskDetails(taskId: string) {
  return useQuery<Task>({
    queryKey: ['task', taskId],
    queryFn: async () => {
      const res = await fetch(`${API_BASE}/api/tasks/${taskId}?hydrate=true`);
      if (!res.ok) throw new Error('Failed to fetch task');
      return res.json();
    },
    enabled: !!taskId,
  });
}
```

### 3. Use the Component

```typescript
// In a route page component (e.g., apps/quarry-web/src/routes/tasks/index.tsx)
import { TaskCard } from '../../components/task/TaskCard';
import { useAllTasks } from '../../api/hooks/useAllElements';

function TaskList() {
  const { data: tasks, isLoading } = useAllTasks();

  if (isLoading) return <div>Loading...</div>;

  return (
    <div className="space-y-4">
      {tasks?.map(task => (
        <TaskCard
          key={task.id}
          task={task}
          onClick={() => console.log('Clicked', task.id)}
        />
      ))}
    </div>
  );
}
```

### 4. Handle Real-time Updates

```typescript
import { useRealtimeEvents } from '../../api/hooks/useRealtimeEvents';
import { useQueryClient } from '@tanstack/react-query';

function TaskList() {
  const queryClient = useQueryClient();

  useRealtimeEvents({
    onEvent: (event) => {
      if (event.elementType === 'task') {
        queryClient.invalidateQueries({ queryKey: ['tasks'] });
      }
    },
  });

  // ... rest of component
}
```

### 5. Add Mutations

```typescript
// apps/quarry-web/src/api/hooks/useTaskMutations.ts
import { useMutation, useQueryClient } from '@tanstack/react-query';

const API_BASE = import.meta.env.VITE_API_URL || '';

export function useUpdateTask() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, updates }: { id: string; updates: Partial<Task> }) => {
      const res = await fetch(`${API_BASE}/api/tasks/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(updates),
      });
      if (!res.ok) throw new Error('Failed to update');
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['tasks'] });
    },
  });
}

export function useCloseTask() {
  const updateTask = useUpdateTask();

  return useMutation({
    mutationFn: async ({ id, reason }: { id: string; reason?: string }) => {
      return updateTask.mutateAsync({
        id,
        updates: { status: 'closed', closeReason: reason },
      });
    },
  });
}
```

### 6. Create a Page (if needed)

```typescript
// apps/quarry-web/src/routes/tasks/index.tsx
import { TaskCard } from '../../components/task/TaskCard';
import { useAllTasks } from '../../api/hooks/useAllElements';
import { useState } from 'react';

export function TasksPage() {
  const { data: tasks, isLoading } = useAllTasks();
  const [filter, setFilter] = useState<string>('all');

  if (isLoading) return <div className="p-6">Loading...</div>;

  const filtered = tasks?.filter(t =>
    filter === 'all' || t.status === filter
  );

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">Tasks</h1>
        <select
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          className="border rounded px-3 py-2"
        >
          <option value="all">All</option>
          <option value="open">Open</option>
          <option value="in_progress">In Progress</option>
          <option value="closed">Closed</option>
        </select>
      </div>

      <div className="space-y-4">
        {filtered?.map(task => (
          <TaskCard key={task.id} task={task} />
        ))}
      </div>
    </div>
  );
}
```

### 7. Register the Route

The apps use TanStack Router with `createRouter`/`createRoute`. Routes use a `component` prop (not `element`):

```typescript
// apps/quarry-web/src/router.tsx
import { createRouter, createRoute, createRootRoute } from '@tanstack/react-router';
import { AppShell } from './components/layout';
import { TasksPage } from './routes/tasks';

const rootRoute = createRootRoute({
  component: AppShell,
});

const tasksRoute = createRoute({
  getParentRoute: () => rootRoute,
  path: '/tasks',
  component: TasksPage,
  validateSearch: (search: Record<string, unknown>) => ({
    selected: typeof search.selected === 'string' ? search.selected : undefined,
    page: typeof search.page === 'number' ? search.page : 1,
    limit: typeof search.limit === 'number' ? search.limit : 25,
  }),
});

const routeTree = rootRoute.addChildren([
  // ... existing routes
  tasksRoute,
]);

export const router = createRouter({ routeTree });
```

### 8. Add Sidebar Link

```typescript
// apps/quarry-web/src/components/layout/Sidebar.tsx
const navItems = [
  // ... existing items
  { path: '/tasks', label: 'Tasks', icon: CheckSquare },
];
```

## Styling Patterns

### Conditional Classes

The codebase uses template literals for conditional class names (there is no `cn()` utility):

```typescript
<div className={`base-classes ${isActive ? 'active-classes' : ''} ${isDisabled ? 'opacity-50 cursor-not-allowed' : ''} ${className ?? ''}`} />
```

For array-based composition (used in `@stoneforge/ui` components):

```typescript
<span
  className={[
    'inline-flex items-center rounded-full font-medium',
    variant === 'success' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800',
    className,
  ].filter(Boolean).join(' ')}
/>
```

### Responsive Design

```typescript
<div className="
  grid grid-cols-1
  md:grid-cols-2
  lg:grid-cols-3
  gap-4
">
  {/* Grid items */}
</div>
```

### Dark Mode (if supported)

```typescript
<div className="
  bg-white text-gray-900
  dark:bg-gray-800 dark:text-white
">
  {/* Content */}
</div>
```

## Testing

```typescript
// apps/quarry-web/src/components/task/TaskCard.test.tsx
import { render, screen, fireEvent } from '@testing-library/react';
import { TaskCard } from './TaskCard';

describe('TaskCard', () => {
  const mockTask = {
    id: 'task-1',
    type: 'task' as const,
    title: 'Test Task',
    status: 'open',
    tags: ['urgent'],
    // ... other required fields
  };

  it('renders task title', () => {
    render(<TaskCard task={mockTask} />);
    expect(screen.getByText('Test Task')).toBeInTheDocument();
  });

  it('calls onClick when clicked', () => {
    const onClick = jest.fn();
    render(<TaskCard task={mockTask} onClick={onClick} />);
    fireEvent.click(screen.getByText('Test Task'));
    expect(onClick).toHaveBeenCalled();
  });
});
```

## Checklist

- [ ] Component file created with TypeScript types
- [ ] Props interface defined
- [ ] Styling with Tailwind (template literals or array join for class composition)
- [ ] Data fetching hook added (if needed)
- [ ] Mutations added (if needed)
- [ ] Real-time updates handled (if needed)
- [ ] Page component created (if needed)
- [ ] Route registered in router.tsx (TanStack Router with createRoute/component prop)
- [ ] Sidebar link added (if needed)
- [ ] Tests written
